        const admResp = (null == (_b = empAdm.responsavel) ? void 0 : _b.nome) || empAdm.respNome || (null == assinaturaMaster ? void 0 : assinaturaMaster.nome) || "", admNac = (null == (_c = empAdm.responsavel) ? void 0 : _c.nacionalidade) || empAdm.respNacionalidade || "brasileiro(a)", admEc = _ecTexto((null == (_d = empAdm.responsavel) ? void 0 : _d.ec) || empAdm.respEc), admRg = (null == (_e = empAdm.responsavel) ? void 0 : _e.rg) || empAdm.respRg || "", admCpf = (null == (_f = empAdm.responsavel) ? void 0 : _f.cpf) || empAdm.respCpf || (null == assinaturaMaster ? void 0 : assinaturaMaster.cpfCnpj) || "";
